    hint:"Fiber.new { ... }.resume と Fiber.yield でコンテキストを切り替えます。",
    answer:
`class Scheduler
  def initialize
    @queue = []
  end

  def spawn(&block)
    @queue << Fiber.new(&block)
  end

  def run
    until @queue.empty?
      fiber = @queue.shift
      begin
        fiber.resume
        @queue << fiber if fiber.alive?
      rescue FiberError
      end
    end
  end
end

def task(name, steps)
  steps.times do |i|
    puts "#{name}: step #{i}"
    Fiber.yield
  end
  puts "#{name}: done"
end

sched = Scheduler.new
sched.spawn { task('A', 3) }
sched.spawn { task('B', 2) }
sched.spawn { task('C', 3) }
sched.run`,
