    answer:
`use std::borrow::Cow;

fn ensure_uppercase(s: &str) -> Cow<str> {
    if s.chars().all(|c| c.is_uppercase() || !c.is_alphabetic()) {
        Cow::Borrowed(s)
    } else {
        Cow::Owned(s.to_uppercase())
    }
}

fn main() {
    let s1 = "HELLO";
    let s2 = "world";
    let r1 = ensure_uppercase(s1);
    let r2 = ensure_uppercase(s2);
    println!("{}", r1);
    println!("{}", r2);
}`,
    expected:"HELLO\nWORLD",
